import React, { useState } from "react";

const Filters = ({
                     yearRange,
                     setYearRange,
                     widthRange,
                     setWidthRange,
                     heightRange,
                     setHeightRange,
                     unit,
                     setUnit,
                     filterData,
                 }) => {
    const handleRangeChange = (e, setRange) => {
        const { name, value } = e.target;
        setRange(prev => (name === "min" ? [parseInt(value), prev[1]] : [prev[0], parseInt(value)]));
        filterData();
    };

    const handleUnitChange = (e) => {
        setUnit(e.target.value);
        filterData();
    };

    return (
        <aside className="filters">
            <h2>Filters</h2>

            {/* Year Range Slider */}
            <div className="filter-section">
                <label>Year Range:</label>
                <input
                    type="range"
                    name="min"
                    min="2011"
                    max="2025"
                    value={yearRange[0]}
                    onChange={e => handleRangeChange(e, setYearRange)}
                />
                <input
                    type="range"
                    name="max"
                    min="2011"
                    max="2025"
                    value={yearRange[1]}
                    onChange={e => handleRangeChange(e, setYearRange)}
                />
                <span>{yearRange[0]} - {yearRange[1]}</span>
            </div>

            {/* Unit Toggle */}
            <div className="filter-section">
                <label htmlFor="unit-select">Dimensions Unit:</label>
                <select id="unit-select" value={unit} onChange={handleUnitChange}>
                    <option value="Dimensions (inches)">Inches</option>
                    <option value="Dimensions (cm)">Centimeters</option>
                </select>
            </div>

            {/* Width Slider */}
            <div className="filter-section">
                <label>Width ({unit}):</label>
                <input
                    type="range"
                    name="min"
                    min="0"
                    max="100"
                    value={widthRange[0]}
                    onChange={e => handleRangeChange(e, setWidthRange)}
                />
                <input
                    type="range"
                    name="max"
                    min="0"
                    max="100"
                    value={widthRange[1]}
                    onChange={e => handleRangeChange(e, setWidthRange)}
                />
                <span>{widthRange[0]} - {widthRange[1]} {unit}</span>
            </div>

            {/* Height Slider */}
            <div className="filter-section">
                <label>Height ({unit}):</label>
                <input
                    type="range"
                    name="min"
                    min="0"
                    max="100"
                    value={heightRange[0]}
                    onChange={e => handleRangeChange(e, setHeightRange)}
                />
                <input
                    type="range"
                    name="max"
                    min="0"
                    max="100"
                    value={heightRange[1]}
                    onChange={e => handleRangeChange(e, setHeightRange)}
                />
                <span>{heightRange[0]} - {heightRange[1]} {unit}</span>
            </div>
        </aside>
    );
};

export default Filters;
